export type DeploymentState =
  | { status: "idle" }
  | { status: "running"; id: string; target: string }
  | { status: "succeeded"; id: string; target: string; at: string }
  | { status: "rolled-back"; id: string; reason: string };

export type DeploymentCommand =
  | { type: "start"; id: string; target: string }
  | { type: "succeed"; at: string }
  | { type: "rollback"; reason: string };

export type DeploymentEvent =
  | { type: "DeploymentStarted"; id: string; target: string }
  | { type: "DeploymentSucceeded"; at: string }
  | { type: "DeploymentRolledBack"; reason: string };

export class DeploymentError extends Error {
  constructor(code: string) { super(code); this.name = "DeploymentError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const deploymentDecider: Decider<DeploymentCommand, DeploymentEvent, DeploymentState> = {
  initialState: { status: "idle" },
  decide(c, s) {
    switch (c.type) {
      case "start":
        if (s.status !== "idle") throw new DeploymentError("IN_PROGRESS");
        return [{ type: "DeploymentStarted", id: c.id, target: c.target }];
      case "succeed":
        if (s.status !== "running") throw new DeploymentError("NOT_RUNNING");
        return [{ type: "DeploymentSucceeded", at: c.at }];
      case "rollback":
        if (s.status === "succeeded") throw new DeploymentError("ALREADY_SUCCEEDED");
        if (s.status !== "running") throw new DeploymentError("NOT_RUNNING");
        return [{ type: "DeploymentRolledBack", reason: c.reason }];
      default: { const _n: never = c; throw new DeploymentError("UNKNOWN"); }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "DeploymentStarted":
        return { status: "running", id: e.id, target: e.target };
      case "DeploymentSucceeded":
        if (s.status !== "running") return s;
        return { status: "succeeded", id: s.id, target: s.target, at: e.at };
      case "DeploymentRolledBack":
        if (s.status !== "running") return s;
        return { status: "rolled-back", id: s.id, reason: e.reason };
      default: { const _n: never = e; return s; }
    }
  },
};
```

A Decider packages `initialState`, `decide`, and `evolve` for one aggregate. `decide` validates a command against state and returns events or throws a typed error. `evolve` is a pure reducer that folds each event back into state. No I/O lives inside — the core is deterministic and trivially testable.

