export type IncidentState =
  | { status: "none" }
  | { status: "open"; id: string; severity: "low" | "high" }
  | { status: "acknowledged"; id: string; severity: "low" | "high"; by: string }
  | { status: "resolved"; id: string; at: string };

export type IncidentCommand =
  | { type: "open"; id: string; severity: "low" | "high" }
  | { type: "ack"; by: string }
  | { type: "resolve"; at: string };

export type IncidentEvent =
  | { type: "IncidentOpened"; id: string; severity: "low" | "high" }
  | { type: "IncidentAcknowledged"; by: string }
  | { type: "IncidentResolved"; at: string };

export class IncidentError extends Error {}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const incidentDecider: Decider<IncidentCommand, IncidentEvent, IncidentState> = {
  initialState: { status: "none" },
  decide(c, s) {
    switch (c.type) {
      case "open":
        if (s.status !== "none") throw new IncidentError("EXISTS");
        return [{ type: "IncidentOpened", id: c.id, severity: c.severity }];
      case "ack":
        if (s.status !== "open") throw new IncidentError("NOT_OPEN");
        return [{ type: "IncidentAcknowledged", by: c.by }];
      case "resolve":
        if (s.status === "resolved") throw new IncidentError("DONE");
        if (s.status === "none") throw new IncidentError("UNKNOWN");
        return [{ type: "IncidentResolved", at: c.at }];
      default: { const _n: never = c; throw new IncidentError("UNKNOWN_CMD"); }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "IncidentOpened":
        return { status: "open", id: e.id, severity: e.severity };
      case "IncidentAcknowledged":
        if (s.status !== "open") return s;
        return { status: "acknowledged", id: s.id, severity: s.severity, by: e.by };
      case "IncidentResolved":
        if (s.status === "none") return s;
        return { status: "resolved", id: "id" in s ? s.id : "", at: e.at };
      default: { const _n: never = e; return s; }
    }
  },
};
