    switch (e.type) {
      case "RenewalRequested":
        return { status: "requested", id: e.id, term: e.term };
      case "RenewalConfirmed":
        if (s.status !== "requested") return s;
        return { status: "confirmed", id: s.id, term: s.term, at: e.at };
      case "RenewalDeclined":
