export type PipelineEvent =
  | { type: "PipelineCreated"; id: string; name: string }
  | { type: "StageStarted"; stage: string }
  | { type: "StageFinished"; stage: string; success: boolean }
  | { type: "PipelineArchived"; at: string };

export type PipelineView = {
  id: string;
  name: string;
  stageCount: number;
  lastStatus: "pending" | "running" | "passed" | "failed";
};

export const emptyView: PipelineView = {
  id: "",
  name: "",
  stageCount: 0,
  lastStatus: "pending",
};

export function project(view: PipelineView, event: PipelineEvent): PipelineView {
  switch (event.type) {
    case "PipelineCreated":
      return { id: event.id, name: event.name, stageCount: 0, lastStatus: "pending" };
    case "StageStarted":
      return { ...view, stageCount: view.stageCount + 1, lastStatus: "running" };
    case "StageFinished":
      return { ...view, lastStatus: event.success ? "passed" : "failed" };
    case "PipelineArchived":
      return view;
    default: {
      const _n: never = event;
      return view;
    }
  }
}

export function projectAll(events: PipelineEvent[]): PipelineView {
  return events.reduce<PipelineView>(project, emptyView);
}
