export type RunbookEvent =
  | { type: "RunbookAuthored"; id: string; title: string }
  | { type: "StepAdded"; stepId: string }
  | { type: "StepRemoved"; stepId: string }
  | { type: "RunbookRetired"; at: string };

export type RunbookView = {
  id: string;
  title: string;
  steps: number;
  retired: boolean;
};

export const emptyRunbookView: RunbookView = {
  id: "",
  title: "",
  steps: 0,
  retired: false,
};

export function project(view: RunbookView, event: RunbookEvent): RunbookView {
  switch (event.type) {
    case "RunbookAuthored":
      return { id: event.id, title: event.title, steps: 0, retired: false };
    case "StepAdded":
      return { ...view, steps: view.steps + 1 };
    case "StepRemoved":
      return { ...view, steps: Math.max(0, view.steps - 1) };
    case "RunbookRetired":
      return { ...view, retired: true };
    default: {
      const _n: never = event;
      return view;
    }
  }
}

export function projection(events: RunbookEvent[]): RunbookView {
  return events.reduce<RunbookView>(project, emptyRunbookView);
}
```

A projection is a pure fold. Start with an initial view, and step through events updating the fields you care about. Events outside the view's interest are returned unchanged — the projection stays narrow.

