```typescript
export type AlertStateV1 = { id: string; raised: boolean };
export type AlertStateV2 = { id: string; raised: boolean; level: number };
export type AlertStateV3 = { id: string; status: "quiet" | "raised" | "cleared"; level: number };

export type CurrentAlertState = AlertStateV3;

export type Snapshot<S> = { version: number; state: S };

export const CURRENT_VERSION = 3;

function v1Tov2(s: AlertStateV1): AlertStateV2 {
  return { id: s.id, raised: s.raised, level: 0 };
}

function v2Tov3(s: AlertStateV2): AlertStateV3 {
  return { id: s.id, status: s.raised ? "raised" : "quiet", level: s.level };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentAlertState> {
  let v = snap.version;
  let s: unknown = snap.state;
  if (v === 1) { s = v1Tov2(s as AlertStateV1); v = 2; }
  if (v === 2) { s = v2Tov3(s as AlertStateV2); v = 3; }
  if (v !== CURRENT_VERSION) throw new Error(`UNSUPPORTED_${v}`);
  return { version: CURRENT_VERSION, state: s as CurrentAlertState };
}

export function serialise(state: CurrentAlertState): Snapshot<CurrentAlertState> {
  return { version: CURRENT_VERSION, state };
}

export function load(raw: Snapshot<unknown>): CurrentAlertState {
  const snap = upgradeSnapshot(raw);
  if (snap.version !== CURRENT_VERSION) throw new Error("UPGRADE_FAILED");
  return snap.state;
}
