export type AlertEvent =
  | { type: "AlertRaised"; id: string; level: number }
  | { type: "AlertCleared"; id: string; at: string };

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface OutboxRow {
  id: string;
  payload: string;
  publishedAt: string | null;
}

export interface Transaction {
  appendToStream(stream: string, events: AlertEvent[], opts: { expectedRevision: ExpectedRevision }): Promise<void>;
  insertOutbox(rows: OutboxRow[]): Promise<void>;
}

export interface UnitOfWork {
  run<A>(fn: (tx: Transaction) => Promise<A>): Promise<A>;
}

// The publisher worker polls outbox rows WHERE publishedAt IS NULL, posts each
// payload to the target broker, then marks the row as published in a second tx.
// It runs independently of the write path below.
export async function appendWithOutbox(
  stream: string,
  events: AlertEvent[],
  rows: OutboxRow[],
  expectedRevision: ExpectedRevision,
  uow: UnitOfWork,
): Promise<void> {
  await uow.run(async (tx) => {
    await tx.appendToStream(stream, events, { expectedRevision });
    await tx.insertOutbox(rows);
  });
}
